mapper.select:
SELECT p.* from fc_payment p left join
uc_supplier s on p.supplierId = s.id WHERE 1 = 1


    AND (
    p.`code` LIKE concat('%', #{query.name}, '%') OR
    s.`code` LIKE concat('%', #{query.name}, '%') OR
    s.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND p.`issueDate`  >=  #{query.startDate}


    AND p.`issueDate`  <=  #{query.endDate}


ORDER BY p.createdTime DESC
